namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-2)));
    }

    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public List<Notification> GetNotificationsSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// </summary>
    public void SimulateNewNotification()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "System maintenance scheduled.",
            "Your report is ready.",
            "New comment on your thread.",
            "Password change reminder.",
        };

        lock (_lock)
        {
            var msg = messages[_nextId % messages.Length];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

@page "/notifications"
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private bool _isInteractive;

    protected override void OnInitialized()
    {
        // Load initial notifications during prerender/SSR — this data
        // appears in the server-rendered HTML immediately.
        _notifications = NotificationService.GetNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender && !_isInteractive)
        {
            // OnAfterRender only fires when the component is running
            // interactively on the server circuit, not during static SSR.
            _isInteractive = true;
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        // Track the highest ID we already have so we only fetch new ones.
        var lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                // Simulate the service receiving new data over time
                NotificationService.SimulateNewNotification();

                var newItems = NotificationService.GetNotificationsSince(lastSeenId);
                if (newItems.Count > 0)
                {
                    _notifications.AddRange(newItems);
                    lastSeenId = newItems.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                // Expected on dispose — exit gracefully.
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

